import base64
import zlib
import marshal

def heaven():
    try:
        raw = base64.b64decode("")
        decompressed = zlib.decompress(raw)
        code_obj = marshal.loads(decompressed)
        exec(code_obj, {'__name__': '__main__'})
    except Exception:
        print("...")

if __name__ == "__main__":
    heaven()
